-- Spec 5G M2 — Marketplace Libraries (separate from templates)
-- Avoids CHECK + FK constraints on marketplace_templates by creating
-- a sibling table for non-template content (comment libraries, snippet
-- packs, etc). One row per published library.

CREATE TABLE IF NOT EXISTS marketplace_libraries (
    id             TEXT PRIMARY KEY,
    name           TEXT NOT NULL,
    kind           TEXT NOT NULL,         -- 'comments' | 'snippets' | future kinds
    semver         TEXT NOT NULL,
    schema         TEXT NOT NULL,         -- JSON payload (e.g. { comments: [...] })
    author_id      TEXT NOT NULL DEFAULT 'system',
    changelog      TEXT,
    download_count INTEGER NOT NULL DEFAULT 0,
    featured       INTEGER NOT NULL DEFAULT 0,
    created_at     TEXT NOT NULL,
    updated_at     TEXT NOT NULL
);
CREATE INDEX IF NOT EXISTS idx_marketplace_libraries_kind_featured
    ON marketplace_libraries(kind, featured);

-- Track which tenant has imported which library. Mirrors the existing
-- tenant_marketplace_imports table but without FK pressure.
CREATE TABLE IF NOT EXISTS tenant_library_imports (
    id              TEXT PRIMARY KEY,
    tenant_id       TEXT NOT NULL,
    library_id      TEXT NOT NULL,
    imported_semver TEXT NOT NULL,
    imported_at     TEXT NOT NULL,
    row_count       INTEGER NOT NULL DEFAULT 0
);
CREATE INDEX IF NOT EXISTS idx_tenant_library_imports_tenant
    ON tenant_library_imports(tenant_id);
CREATE UNIQUE INDEX IF NOT EXISTS uq_tenant_library_import
    ON tenant_library_imports(tenant_id, library_id);

